@namespace sv_7aed748fa0ad472d917dc6ebbd625e0e.Components.Pages.Catalog

<div class="p-3 border rounded bg-light">
    <h5 class="mb-3">Filters</h5>

    <div class="mb-3">
        <label class="form-label fw-bold">Categories</label>
        @foreach (var category in Categories)
        {
            <div class="form-check">
                <input class="form-check-input" type="checkbox" id="@($"cat-{category}")"
                       checked="@(_selectedCategories.Contains(category))"
                       @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                <label class="form-check-label" for="@($"cat-{category}")">@category</label>
            </div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label fw-bold">Price Range</label>
        <div class="d-flex gap-2 align-items-center">
            <input type="number" class="form-control form-control-sm" placeholder="Min"
                   value="@_minPrice" @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <span>–</span>
            <input type="number" class="form-control form-control-sm" placeholder="Max"
                   value="@_maxPrice" @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="form-check mb-3">
        <input class="form-check-input" type="checkbox" id="inStockOnly"
               checked="@_inStockOnly"
               @onchange="@(e => _inStockOnly = (bool)(e.Value ?? false))" />
        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
    </div>

    <div class="d-grid gap-2">
        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public ProductFilter? CurrentFilter { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    [Parameter]
    public EventCallback OnClearFilters { get; set; }

    private HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    protected override void OnParametersSet()
    {
        if (CurrentFilter is not null)
        {
            _selectedCategories = CurrentFilter.Categories is not null
                ? new HashSet<string>(CurrentFilter.Categories)
                : [];
            _minPrice = CurrentFilter.MinPrice;
            _maxPrice = CurrentFilter.MaxPrice;
            _inStockOnly = CurrentFilter.InStockOnly;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnClearFilters.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

@namespace sv_7aed748fa0ad472d917dc6ebbd625e0e.Components.Pages.Catalog

<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div>
        <label class="form-label mb-0 me-2 fw-bold">Sort by:</label>
        <select class="form-select form-select-sm d-inline-block w-auto"
                value="@SortBy"
                @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A-Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>
    <div class="text-muted">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            <span>Showing @start–@end of @TotalCount products</span>
        }
    </div>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        await OnSortChanged.InvokeAsync(e.Value?.ToString() ?? "price_asc");
    }
}

@namespace sv_7aed748fa0ad472d917dc6ebbd625e0e.Components.Pages.Catalog

@if (TotalPages > 1)
{
    <nav aria-label="Product pagination" class="mt-4">
        <ul class="pagination justify-content-center">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage - 1))"
                        disabled="@(CurrentPage <= 1)">
                    Previous
                </button>
            </li>

            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(page))">@page</button>
                </li>
            }

            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" @onclick="@(() => GoToPage(CurrentPage + 1))"
                        disabled="@(CurrentPage >= TotalPages)">
                    Next
                </button>
            </li>
        </ul>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; } = 1;

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private int TotalPages => (int)Math.Ceiling((double)TotalCount / PageSize);

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
            return Enumerable.Range(1, TotalPages);

        var start = Math.Max(1, CurrentPage - maxVisible / 2);
        var end = Math.Min(TotalPages, start + maxVisible - 1);
        if (end - start < maxVisible - 1)
            start = Math.Max(1, end - maxVisible + 1);

        return Enumerable.Range(start, end - start + 1);
    }
}

@page "/catalog"
@namespace sv_7aed748fa0ad472d917dc6ebbd625e0e.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

<div class="row">
    @* Sidebar filters *@
    <div class="col-md-3">
        <CatalogFilters Categories="_categories"
                        CurrentFilter="_filter"
                        OnApplyFilters="HandleApplyFilters"
                        OnClearFilters="HandleClearFilters" />
    </div>

    @* Main content *@
    <div class="col-md-9">
        @if (_error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @_error
            </div>
        }
        else if (_loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_result is not null)
        {
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_result.TotalCount"
                            Page="_result.Page"
                            PageSize="_pageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_result.Items.Count == 0)
            {
                <div class="alert alert-info text-center" role="alert">
                    No products found matching your criteria.
                </div>
            }
            else
            {
                <ProductGrid Products="_result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination CurrentPage="_result.Page"
                                   TotalCount="_result.TotalCount"
                                   PageSize="_pageSize"
                                   OnPageChanged="HandlePageChanged" />
            }
        }
    </div>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private PagedResult<Product>? _result;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int _pageSize = 12;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _loading = true;
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
            await Task.WhenAll(categoriesTask, productsTask);

            _categories = categoriesTask.Result;
            _result = productsTask.Result;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, _pageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — integrate with cart service
        return Task.CompletedTask;
    }
}

